// Helper to draw rounded rectangle path
const drawRoundedRect = (ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, r: number) => {
  if (w < 2 * r) r = w / 2;
  if (h < 2 * r) r = h / 2;
  ctx.beginPath();
  ctx.moveTo(x + r, y);
  ctx.arcTo(x + w, y, x + w, y + h, r);
  ctx.arcTo(x + w, y + h, x, y + h, r);
  ctx.arcTo(x, y + h, x, y, r);
  ctx.arcTo(x, y, x + w, y, r);
  ctx.closePath();
}

const SingleIconCanvas: React.FC<{ 
    item: IconItem; 
    data: IconAdjusterData; 
    isSelected: boolean;
    onSelect: (e: React.MouseEvent) => void;
    onDelete: () => void;
}> = ({ item, data, isSelected, onSelect, onDelete }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        const loadImg = (src: string) => new Promise<HTMLImageElement | null>((resolve) => {
            const img = new Image();
            img.crossOrigin = "Anonymous";
            img.onload = () => resolve(img);
            img.onerror = () => {
                console.warn("Failed to load image:", src);
                resolve(null);
            };
            img.src = src;
        });

        const render = async () => {
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            if (data.background === 'white') {
                ctx.fillStyle = '#ffffff';
                ctx.fillRect(0, 0, canvas.width, canvas.height);
            } else if (data.background === 'black') {
                ctx.fillStyle = '#000000';
                ctx.fillRect(0, 0, canvas.width, canvas.height);
            } else if (data.background === 'custom') {
                ctx.fillStyle = data.backgroundColor;
                ctx.fillRect(0, 0, canvas.width, canvas.height);
            }

            try {
                const [img, overlayImg] = await Promise.all([
                    loadImg(item.src),
                    item.overlay ? loadImg(item.overlay.src) : Promise.resolve(null)
                ]);

                if (!img) return;

                const centerX = canvas.width / 2 + item.x;
                const centerY = canvas.height / 2 + item.y;
                const dw = img.naturalWidth * item.scale;
                const dh = img.naturalHeight * item.scale;
                const dx = centerX - dw / 2;
                const dy = centerY - dh / 2;

                if (data.maskEnabled) {
                     // === MASK MODE ===
                     const inset = data.maskInset || 0;
                     const mx = dx + inset;
                     const my = dy + inset;
                     const mw = dw - (inset * 2);
                     const mh = dh - (inset * 2);

                     // 1. Draw Stroke (around the mask shape)
                     if (data.strokeEnabled && data.strokeThickness > 0) {
                         ctx.save();
                         ctx.lineWidth = data.strokeThickness;
                         ctx.strokeStyle = data.strokeColor;
                         ctx.lineJoin = 'round';
                         ctx.lineCap = 'round';
                         ctx.shadowColor = data.strokeColor;
                         ctx.shadowBlur = data.strokeBlur || 0;
                         // Draw stroke multiple times or just once depending on smoothness needs
                         // Standard stroke on path
                         drawRoundedRect(ctx, mx, my, Math.max(0, mw), Math.max(0, mh), data.maskRadius);
                         ctx.stroke();
                         ctx.restore();
                     }

                     // 2. Clip and Draw Image
                     if (mw > 0 && mh > 0) {
                        ctx.save();
                        drawRoundedRect(ctx, mx, my, mw, mh, data.maskRadius);
                        ctx.clip();
                        ctx.drawImage(img, dx, dy, dw, dh);
                        ctx.restore();
                     }

                } else {
                     // === STANDARD MODE (Shadow based on alpha) ===
                    if (data.strokeEnabled && data.strokeThickness > 0) {
                        ctx.save();
                        const thick = data.strokeThickness;
                        const steps = data.strokeSmoothness || 8;

                        ctx.shadowColor = data.strokeColor;
                        ctx.shadowBlur = data.strokeBlur || 0;

                        const offsets = [];
                        for (let i = 0; i < steps; i++) {
                            const angle = (i / steps) * 2 * Math.PI;
                            offsets.push([Math.cos(angle) * thick, Math.sin(angle) * thick]);
                        }

                        offsets.forEach(([ox, oy]) => {
                           ctx.shadowOffsetX = ox;
                           ctx.shadowOffsetY = oy;
                           ctx.drawImage(img, dx, dy, dw, dh);
                        });

                        ctx.restore();
                    }
                    ctx.drawImage(img, dx, dy, dw, dh);
                }

                if (overlayImg && item.overlay) {
                    ctx.save();
                    ctx.translate(canvas.width / 2, canvas.height / 2);
                    ctx.translate(item.overlay.x, item.overlay.y);
                    ctx.rotate((item.overlay.rotation || 0) * Math.PI / 180);
                    ctx.scale(item.overlay.scale, item.overlay.scale);
                    ctx.drawImage(overlayImg, -overlayImg.naturalWidth / 2, -overlayImg.naturalHeight / 2);
                    ctx.restore();
                }

                if (data.fitPadding > 0) {
                    ctx.save();
                    ctx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
                    ctx.lineWidth = 1;
                    ctx.setLineDash([5, 5]);
                    const p = data.fitPadding;
                    ctx.strokeRect(p, p, canvas.width - p * 2, canvas.height - p * 2);
                    ctx.restore();
                }

            } catch (e) {
                console.error("Render error", e);
            }
        };

        render();

    }, [item, data]); 

    const checkerColor = data.checkeredMode === 'light' ? '#e4e4e7' : '#1f1f22';
    const checkerBg = data.checkeredMode === 'light' ? '#ffffff' : 'transparent';

    return (
        <div 
            className={`relative group flex flex-col gap-2 p-1 border-2 rounded-xl overflow-hidden transition-all duration-300 ${isSelected ? 'border-indigo-500 shadow-lg shadow-indigo-500/20 ring-1 ring-indigo-500 scale-[1.02] bg-indigo-500/5' : 'border-zinc-800/50 hover:border-zinc-600 hover:bg-zinc-800/20'}`}
            onClick={onSelect}
        >
            <div className="relative aspect-square overflow-hidden rounded-lg">
                <canvas 
                    ref={canvasRef} 
                    width={data.canvasWidth} 
                    height={data.canvasHeight} 
                    className="w-full h-auto"
                    style={{
                        backgroundColor: data.background === 'transparent' ? checkerBg : 'transparent',
                        backgroundImage: data.background === 'transparent' ? `linear-gradient(45deg, ${checkerColor} 25%, transparent 25%), linear-gradient(-45deg, ${checkerColor} 25%, transparent 25%), linear-gradient(45deg, transparent 75%, ${checkerColor} 75%), linear-gradient(-45deg, transparent 75%, ${checkerColor} 75%)` : 'none',
                        backgroundSize: '16px 16px',
                        backgroundPosition: '0 0, 0 8px, 8px -8px, -8px 0px'
                    }}
                />
                <button onClick={(e) => { e.stopPropagation(); onDelete(); }} className="absolute top-2 right-2 bg-black/60 hover:bg-red-500 text-white rounded-full p-1.5 opacity-0 group-hover:opacity-100 transition shadow-lg z-10"><CloseIcon className="w-3.5 h-3.5" /></button>
            </div>
            <div className={`px-2 pb-1 text-[10px] font-medium text-center truncate ${isSelected ? 'text-indigo-300' : 'text-zinc-500 group-hover:text-zinc-300'} transition-colors duration-300`}>
                {item.file.name}
            </div>
        </div>
    );
};

const IconAdjuster: React.FC<Props> = ({ state, handleIconUpload, updateIconAdjusterData, updateIconItem }) => {
  const data = state.iconAdjusterData;
  const t = TRANSLATIONS[state.language];
  const fileInputRef = useRef<HTMLInputElement>(null);
  const overlayInputRef = useRef<HTMLInputElement>(null);
  const [lastClickedId, setLastClickedId] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [isDraggingOverlay, setIsDraggingOverlay] = useState(false);
  const [zipName, setZipName] = useState("");
  const [overlayOriginalSize, setOverlayOriginalSize] = useState<{w: number, h: number} | null>(null);

  const getSortedItems = () => {
    const items = [...data.items];
    switch (data.sortOrder) {
        case 'name_asc':
            return items.sort((a, b) => a.file.name.localeCompare(b.file.name));
        case 'name_desc':
            return items.sort((a, b) => b.file.name.localeCompare(a.file.name));
        case 'newest':
            return items.sort((a, b) => parseFloat(b.id) - parseFloat(a.id));
        case 'oldest':
            return items.sort((a, b) => parseFloat(a.id) - parseFloat(b.id));
        case 'original':
        default:
            return items;
    }
  };

  const sortedItems = getSortedItems();

  const getTargetIds = () => {
      if (data.commandMode === 'all') {
          return data.items.map(i => i.id);
      }
      return data.selectedItemIds;
  };

  const primarySelectedItem = data.items.find(i => i.id === data.selectedItemIds[0]);

  // Main Upload Drag and Drop Handlers
  const onDragOver = (e: React.DragEvent) => {
      e.preventDefault(); e.stopPropagation();
      setIsDragging(true);
  };
  const onDragLeave = (e: React.DragEvent) => {
      e.preventDefault(); e.stopPropagation();
      setIsDragging(false);
  };
  const onDrop = (e: React.DragEvent) => {
      e.preventDefault(); e.stopPropagation();
      setIsDragging(false);
      if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
          handleIconUpload(e.dataTransfer.files);
      }
  };

  // Overlay Helper
  const processOverlayFile = (file: File) => {
    const targetIds = getTargetIds();
    if (targetIds.length === 0) {
        alert("Select at least one item to add overlay.");
        return;
    }

    const url = URL.createObjectURL(file);
    const newOverlay: IconOverlay = {
        src: url,
        x: 0,
        y: 0,
        scale: 1,
        rotation: 0
    };

    updateIconItem(targetIds, { overlay: newOverlay });
  };

  const handleOverlayUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      processOverlayFile(file);
      e.target.value = '';
  };

  // Overlay Drag and Drop Handlers
  const onOverlayDragOver = (e: React.DragEvent) => {
    e.preventDefault(); e.stopPropagation();
    setIsDraggingOverlay(true);
  };

  const onOverlayDragLeave = (e: React.DragEvent) => {
    e.preventDefault(); e.stopPropagation();
    setIsDraggingOverlay(false);
  };

  const onOverlayDrop = (e: React.DragEvent) => {
    e.preventDefault(); e.stopPropagation();
    setIsDraggingOverlay(false);
    const file = e.dataTransfer.files?.[0];
    if (file) {
        processOverlayFile(file);
    }
  };

  const updateOverlayProp = (key: keyof IconOverlay, value: number) => {
      const targetIds = getTargetIds();
      const newItems = data.items.map(item => {
          if (targetIds.includes(item.id) && item.overlay) {
              return {
                  ...item,
                  overlay: { ...item.overlay, [key]: value }
              };
          }
          return item;
      });
      updateIconAdjusterData({ items: newItems });
  };

  const removeOverlay = () => {
      const targetIds = getTargetIds();
      const newItems = data.items.map(item => {
          if (targetIds.includes(item.id)) {
              const { overlay, ...rest } = item;
              return rest;
          }
          return item;
      });
      updateIconAdjusterData({ items: newItems });
  };

  // Get dimensions of the overlay image when it changes
  useEffect(() => {
    if (primarySelectedItem?.overlay?.src) {
        const img = new Image();
        img.src = primarySelectedItem.overlay.src;
        img.onload = () => {
            setOverlayOriginalSize({ w: img.naturalWidth, h: img.naturalHeight });
        };
    } else {
        setOverlayOriginalSize(null);
    }
  }, [primarySelectedItem?.overlay?.src]);

  const calculateCrop = (item: IconItem): Promise<Partial<IconItem> | null> => {
      return new Promise((resolve) => {
          const img = new Image();
          img.crossOrigin = "Anonymous";
          img.src = item.src;
          img.onload = () => {
              const cvs = document.createElement('canvas');
              cvs.width = img.naturalWidth;
              cvs.height = img.naturalHeight;
              const ctx = cvs.getContext('2d');
              if(!ctx) { resolve(null); return; }
              ctx.drawImage(img, 0, 0);
              const pixels = ctx.getImageData(0,0, cvs.width, cvs.height).data;

              let minX = cvs.width, minY = cvs.height, maxX = 0, maxY = 0;
              let found = false;

              for(let y=0; y<cvs.height; y++) {
                  for(let x=0; x<cvs.width; x++) {
                      const alpha = pixels[(y*cvs.width + x)*4 + 3];
                      if(alpha > data.cropThreshold) {
                          if(x < minX) minX = x;
                          if(x > maxX) maxX = x;
                          if(y < minY) minY = y;
                          if(y > maxY) maxY = y;
                          found = true;
                      }
                  }
              }

              if(!found) { resolve(null); return; }

              const bw = maxX - minX + 1;
              const bh = maxY - minY + 1;
              const cx = minX + bw / 2;
              const cy = minY + bh / 2;

              const ox = img.naturalWidth / 2;
              const oy = img.naturalHeight / 2;
              const vx = cx - ox;
              const vy = cy - oy;

              const availableW = data.canvasWidth - (data.fitPadding * 2);
              const availableH = data.canvasHeight - (data.fitPadding * 2);
              const scaleW = availableW / bw;
              const scaleH = availableH / bh;
              const newScale = Math.min(scaleW, scaleH);

              resolve({
                  scale: newScale,
                  x: -vx * newScale,
                  y: -vy * newScale
              });
          };
          img.onerror = () => resolve(null);
      });
  };

  useEffect(() => {
    const handleKeyDown = async (e: KeyboardEvent) => {
        // Prevent triggering controls when typing in input fields
        const target = e.target as HTMLElement;
        if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA') {
            return;
        }

        const targetIds = getTargetIds();
        if (targetIds.length === 0) return;

        const move = data.moveStep;
        const scaleStep = data.scaleStep;
        const key = e.key.toLowerCase();

        if (['w','a','s','d','q','e','r','z'].includes(key)) {
            e.preventDefault();
        }

        let hasChanges = false;
        let newItems = data.items.map(item => {
             if (targetIds.includes(item.id)) {
                 let updates: Partial<IconItem> | null = null;
                 switch(key) {
                    case 'w': updates = { y: item.y - move }; break;
                    case 's': updates = { y: item.y + move }; break;
                    case 'a': updates = { x: item.x - move }; break;
                    case 'd': updates = { x: item.x + move }; break;
                    case 'q': updates = { scale: Math.max(0.01, item.scale - scaleStep) }; break;
                    case 'e': updates = { scale: item.scale + scaleStep }; break;
                    case 'z': updates = { x: 0, y: 0, scale: 1 }; break; // Reset
                 }
                 if (updates) {
                     hasChanges = true;
                     return { ...item, ...updates };
                 }
             }
             return item;
        });

        if (key === 'r') {
             const targetItems = data.items.filter(item => targetIds.includes(item.id));
             if (targetItems.length === 0) return;

             const results = await Promise.all(targetItems.map(async (item) => {
                 const updates = await calculateCrop(item);
                 return { id: item.id, updates };
             }));

             newItems = data.items.map(item => {
                 const res = results.find(r => r.id === item.id);
                 if (res && res.updates) {
                     return { ...item, ...res.updates };
                 }
                 return item;
             });
             updateIconAdjusterData({ items: newItems });

        } else if (hasChanges) {
             updateIconAdjusterData({ items: newItems });
        }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [data.selectedItemIds, data.commandMode, data.items, data.moveStep, data.scaleStep, data.canvasWidth, data.canvasHeight, data.fitPadding, data.cropThreshold]);

  const handleItemClick = (id: string, e: React.MouseEvent) => {
      if (data.commandMode === 'one') {
          updateIconAdjusterData({ selectedItemIds: [id] });
          setLastClickedId(id);
      } else if (data.commandMode === 'multi') {
          if (e.shiftKey && lastClickedId) {
              const idx1 = sortedItems.findIndex(i => i.id === lastClickedId);
              const idx2 = sortedItems.findIndex(i => i.id === id);
              if (idx1 !== -1 && idx2 !== -1) {
                  const start = Math.min(idx1, idx2);
                  const end = Math.max(idx1, idx2);
                  const rangeIds = sortedItems.slice(start, end + 1).map(i => i.id);
                  const newSelection = Array.from(new Set([...data.selectedItemIds, ...rangeIds]));
                  updateIconAdjusterData({ selectedItemIds: newSelection });
              }
          } else if (e.altKey && lastClickedId) {
              const idx1 = sortedItems.findIndex(i => i.id === lastClickedId);
              const idx2 = sortedItems.findIndex(i => i.id === id);
              if (idx1 !== -1 && idx2 !== -1) {
                  const start = Math.min(idx1, idx2);
                  const end = Math.max(idx1, idx2);
                  const rangeIdsToRemove = sortedItems.slice(start, end + 1).map(i => i.id);
                  const newSelection = data.selectedItemIds.filter(sid => !rangeIdsToRemove.includes(sid));
                  updateIconAdjusterData({ selectedItemIds: newSelection });
              }
          } else {
              if (data.selectedItemIds.includes(id)) {
                  updateIconAdjusterData({ selectedItemIds: data.selectedItemIds.filter(sid => sid !== id) });
              } else {
                  updateIconAdjusterData({ selectedItemIds: [...data.selectedItemIds, id] });
              }
          }
          setLastClickedId(id);
      } else {
          updateIconAdjusterData({ selectedItemIds: [id], commandMode: 'one' });
          setLastClickedId(id);
      }
  };

  const isItemSelected = (id: string) => {
      if (data.commandMode === 'all') return true;
      return data.selectedItemIds.includes(id);
  };

  const renderItemToCanvas = (item: IconItem, ctx: CanvasRenderingContext2D) => {
      return new Promise<void>(async (resolve) => {
          const loadImg = (src: string) => new Promise<HTMLImageElement | null>((resolve) => {
              const img = new Image();
              img.crossOrigin = "Anonymous";
              img.onload = () => resolve(img);
              img.onerror = () => resolve(null);
              img.src = src;
          });

          ctx.clearRect(0, 0, data.canvasWidth, data.canvasHeight);

          if (data.background === 'white') {
              ctx.fillStyle = '#ffffff';
              ctx.fillRect(0, 0, data.canvasWidth, data.canvasHeight);
          } else if (data.background === 'black') {
              ctx.fillStyle = '#000000';
              ctx.fillRect(0, 0, data.canvasWidth, data.canvasHeight);
          } else if (data.background === 'custom') {
              ctx.fillStyle = data.backgroundColor;
              ctx.fillRect(0, 0, data.canvasWidth, data.canvasHeight);
          }

          try {
              const [img, overlayImg] = await Promise.all([
                  loadImg(item.src),
                  item.overlay ? loadImg(item.overlay.src) : Promise.resolve(null)
              ]);

              if (!img) { resolve(); return; }

              const centerX = data.canvasWidth / 2 + item.x;
              const centerY = data.canvasHeight / 2 + item.y;
              const dw = img.naturalWidth * item.scale;
              const dh = img.naturalHeight * item.scale;
              const dx = centerX - dw / 2;
              const dy = centerY - dh / 2;

              if (data.maskEnabled) {
                   const inset = data.maskInset || 0;
                   const mx = dx + inset;
                   const my = dy + inset;
                   const mw = dw - (inset * 2);
                   const mh = dh - (inset * 2);

                   if (data.strokeEnabled && data.strokeThickness > 0) {
                        ctx.save();
                        ctx.lineWidth = data.strokeThickness;
                        ctx.strokeStyle = data.strokeColor;
                        ctx.lineJoin = 'round';
                        ctx.lineCap = 'round';
                        ctx.shadowColor = data.strokeColor;
                        ctx.shadowBlur = data.strokeBlur || 0;
                        drawRoundedRect(ctx, mx, my, Math.max(0, mw), Math.max(0, mh), data.maskRadius);
                        ctx.stroke();
                        ctx.restore();
                   }

                   if (mw > 0 && mh > 0) {
                      ctx.save();
                      drawRoundedRect(ctx, mx, my, mw, mh, data.maskRadius);
                      ctx.clip();
                      ctx.drawImage(img, dx, dy, dw, dh);
                      ctx.restore();
                   }
              } else {
                  if (data.strokeEnabled && data.strokeThickness > 0) {
                      ctx.save();
                      const thick = data.strokeThickness;
                      const steps = data.strokeSmoothness || 8;
                      ctx.shadowColor = data.strokeColor;
                      ctx.shadowBlur = data.strokeBlur || 0;
                      const offsets = [];
                      for (let i = 0; i < steps; i++) {
                          const angle = (i / steps) * 2 * Math.PI;
                          offsets.push([Math.cos(angle) * thick, Math.sin(angle) * thick]);
                      }
                      offsets.forEach(([ox, oy]) => {
                          ctx.shadowOffsetX = ox; ctx.shadowOffsetY = oy;
                          ctx.drawImage(img, dx, dy, dw, dh);
                      });
                      ctx.restore();
                  }
                  ctx.drawImage(img, dx, dy, dw, dh);
              }

              if (overlayImg && item.overlay) {
                  ctx.save();
                  ctx.translate(data.canvasWidth / 2, data.canvasHeight / 2);
                  ctx.translate(item.overlay.x, item.overlay.y);
                  ctx.rotate((item.overlay.rotation || 0) * Math.PI / 180);
                  ctx.scale(item.overlay.scale, item.overlay.scale);
                  ctx.drawImage(overlayImg, -overlayImg.naturalWidth / 2, -overlayImg.naturalHeight / 2);
                  ctx.restore();
              }
              resolve();
          } catch (e) { resolve(); }
      });
  };

  const handleSaveZip = async () => {
      const zip = new JSZip();
      const tempCanvas = document.createElement('canvas');
      tempCanvas.width = data.canvasWidth;
      tempCanvas.height = data.canvasHeight;
      const ctx = tempCanvas.getContext('2d');
      if (!ctx) return;

      for (const item of data.items) {
          await renderItemToCanvas(item, ctx);
          const base64Data = tempCanvas.toDataURL('image/png').split(',')[1];
          const originalName = item.file.name.replace(/\.[^/.]+$/, "");
          zip.file(`${originalName}.png`, base64Data, { base64: true });
      }

      const content = await zip.generateAsync({ type: "blob" });
      const url = URL.createObjectURL(content);
      const link = document.createElement('a');
      link.href = url;

      let fileName = zipName.trim();
      if (!fileName) {
          fileName = "Kenji_icons.zip";
      } else {
          if (!fileName.toLowerCase().endsWith('.zip')) {
              fileName += ".zip";
          }
      }

      link.download = fileName;
      link.click();
  };

