  const gridPercent = Math.round(((11 - data.gridColumns) / 9) * 100);

  // Helper to safely calculate display values
  const currentOverlayW = (overlayOriginalSize && primarySelectedItem?.overlay) 
      ? Math.round(overlayOriginalSize.w * primarySelectedItem.overlay.scale) 
      : 0;
  const currentOverlayH = (overlayOriginalSize && primarySelectedItem?.overlay) 
      ? Math.round(overlayOriginalSize.h * primarySelectedItem.overlay.scale) 
      : 0;

  return (
    <div className="flex flex-col md:flex-row h-full overflow-hidden animate-fade-in-up">
        {/* Sidebar Settings */}
        <div className="w-full md:w-80 bg-zinc-900/50 backdrop-blur-md border-r border-zinc-800 p-6 overflow-y-auto custom-scrollbar flex flex-col gap-6">
            <h2 className="text-xl font-bold text-white flex items-center gap-2">
                <span className="text-blue-400">🖼️</span> {t.iconAdjuster.title}
            </h2>

            <div 
                className={`w-full aspect-video border-2 border-dashed rounded-xl transition flex flex-col items-center justify-center cursor-pointer group ${isDragging ? 'border-blue-500 bg-blue-500/10 scale-[1.02]' : 'border-zinc-700/50 bg-zinc-950/30 hover:border-blue-500/50 hover:bg-blue-500/5'}`}
                onClick={() => fileInputRef.current?.click()}
                onDragOver={onDragOver}
                onDragLeave={onDragLeave}
                onDrop={onDrop}
            >
                <input type="file" ref={fileInputRef} multiple accept="image/*" className="hidden" onChange={(e) => e.target.files && handleIconUpload(e.target.files)} />
                <UploadIcon className={`w-8 h-8 mb-2 transition ${isDragging ? 'text-blue-400 scale-110' : 'text-zinc-600 group-hover:text-blue-400'}`} />
                <p className={`text-xs font-bold ${isDragging ? 'text-blue-300' : 'text-zinc-400'}`}>{t.iconAdjuster.uploadTitle}</p>
                <p className="text-[10px] text-zinc-600">{t.iconAdjuster.uploadDesc}</p>
            </div>

            <div className="h-px bg-zinc-800" />

            {/* Selection Mode */}
            <div className="space-y-2">
                <label className="text-xs font-bold text-zinc-500 uppercase tracking-wider">{t.iconAdjuster.selectionMode}</label>
                <div className="flex bg-zinc-950 p-1 rounded-lg border border-zinc-800">
                    {['all', 'one', 'multi'].map(mode => (
                        <button 
                            key={mode}
                            onClick={() => updateIconAdjusterData({ commandMode: mode as any })}
                            className={`flex-1 py-2 text-xs font-bold rounded-md transition-all ${data.commandMode === mode ? 'bg-zinc-800 text-white shadow-sm' : 'text-zinc-500 hover:text-zinc-300'}`}
                        >
                            {mode === 'one' ? t.iconAdjuster.modeOne : mode === 'multi' ? t.iconAdjuster.modeMulti : t.iconAdjuster.modeAll}
                        </button>
                    ))}
                </div>
            </div>

            <div className="h-px bg-zinc-800" />

            {/* Mask Settings */}
            <div className="space-y-4">
                 <h4 className="text-xs font-bold text-zinc-500 uppercase tracking-wider">{t.iconAdjuster.maskTitle}</h4>
                 <label className="flex items-center gap-2 text-sm text-zinc-300">
                     <input type="checkbox" checked={data.maskEnabled} onChange={(e) => updateIconAdjusterData({ maskEnabled: e.target.checked })} className="rounded bg-zinc-800 border-zinc-700 text-blue-500" />
                     {t.iconAdjuster.enableMask}
                 </label>
                 {data.maskEnabled && (
                     <div className="space-y-3 pl-4 border-l border-zinc-800 animate-fade-in">
                         <div className="space-y-1">
                             <div className="flex justify-between">
                                <label className="text-[10px] text-zinc-400">{t.iconAdjuster.maskRadius}</label>
                                <span className="text-[10px] text-zinc-500 font-mono">{data.maskRadius}px</span>
                             </div>
                             <input type="range" min="0" max="256" value={data.maskRadius} onChange={(e) => updateIconAdjusterData({ maskRadius: parseInt(e.target.value) })} className="w-full h-1 bg-zinc-800 rounded appearance-none cursor-pointer accent-blue-500" />
                         </div>
                         <div className="space-y-1">
                             <div className="flex justify-between">
                                <label className="text-[10px] text-zinc-400">{t.iconAdjuster.maskInset}</label>
                                <span className="text-[10px] text-zinc-500 font-mono">{data.maskInset}px</span>
                             </div>
                             <input type="range" min="0" max="100" value={data.maskInset} onChange={(e) => updateIconAdjusterData({ maskInset: parseInt(e.target.value) })} className="w-full h-1 bg-zinc-800 rounded appearance-none cursor-pointer accent-blue-500" />
                         </div>
                     </div>
                 )}
            </div>

            <div className="h-px bg-zinc-800" />

            {/* Overlay Settings */}
            <div className="space-y-4">
                 <h4 className="text-xs font-bold text-zinc-500 uppercase tracking-wider">{t.iconAdjuster.overlayTitle}</h4>

                 <div 
                    className={`flex gap-2 p-1 rounded-xl transition-all border ${isDraggingOverlay ? 'border-blue-500 bg-blue-500/10' : 'border-transparent'}`}
                    onDragOver={onOverlayDragOver}
                    onDragLeave={onOverlayDragLeave}
                    onDrop={onOverlayDrop}
                 >
                     <button 
                        onClick={() => overlayInputRef.current?.click()}
                        className={`flex-1 py-2 ${isDraggingOverlay ? 'bg-blue-600 text-white' : 'bg-zinc-800 hover:bg-zinc-700 text-zinc-300'} rounded-lg text-xs font-medium transition flex items-center justify-center gap-2`}
                     >
                         <UploadIcon className="w-3 h-3" /> {t.iconAdjuster.overlayUpload}
                     </button>
                     <input type="file" ref={overlayInputRef} accept="image/*" className="hidden" onChange={handleOverlayUpload} />
                     {primarySelectedItem?.overlay && (
                         <button onClick={removeOverlay} className="p-2 bg-red-900/30 hover:bg-red-900/50 text-red-400 rounded-lg transition">
                             <DeleteIcon className="w-4 h-4" />
                         </button>
                     )}
                 </div>

                 {primarySelectedItem?.overlay && (
                     <div className="space-y-3 pl-4 border-l border-zinc-800 animate-fade-in">
                         {/* Width & Height Editing */}
                         {overlayOriginalSize && (
                            <div className="grid grid-cols-2 gap-2">
                                <div className="space-y-1">
                                    <label className="text-[10px] text-zinc-400">{t.iconAdjuster.overlayWidth}</label>
                                    <input 
                                        type="number" 
                                        value={currentOverlayW} 
                                        onChange={(e) => {
                                            const w = parseInt(e.target.value) || 0;
                                            if (overlayOriginalSize.w > 0) {
                                                const newScale = w / overlayOriginalSize.w;
                                                updateOverlayProp('scale', newScale);
                                            }
